var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 헬기다!","JPN":"あっ、ヘリだ！","ENG":"Oh, a chopper!","TWN":"啊，直升機！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여기요! 저희 좀 구해주세요오!","JPN":"おーい！　私たちを助けてくださーい！","ENG":"Here! Please save us!","TWN":"這邊！快救救我們！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"관둬. 저건 방송사 헬기야. 목숨 걸고 지금 상황을 중계하러 나온 건데 우릴 도와줄 리가 없지.","JPN":"放っておけ。あれは放送局のヘリだ。命をかけてこの状況を中継しに来たんだから、助けてくれるはずがないだろ。","ENG":"Give up. That's a broadcast helicopter. They're risking their lives to show this situation live. They'll never help us.","TWN":"算了吧，那是電視台的直升機。他們冒著危險出來現場直播，怎麼可能會來救我們。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이런 와중에도 촬영이 우선이라니.","JPN":"人命よりも撮影が優先だなんて。","ENG":"Prioritizing broadcast in a situation like this?","TWN":"這種情況還要拍攝嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"열 받긴 하지만… 샤레이드답네요.","JPN":"ムカつくけど……シャレードらしいわ。","ENG":"It's annoying, but... that's Charade.","TWN":"雖然讓人生氣但不愧是查雷德。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"빨리 여길 뜨자. 교통상황이 멀쩡할지는 모르겠지만.","JPN":"道路の状態が少し心配だが、早くここから出よう。","ENG":"Let's get out of here. I'm not sure how the traffic is, though.","TWN":"我們快離開這裡吧，雖然不知道交通會不會順暢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"차 키는 가져왔지?","JPN":"車のカギ、持ってきただろ？","ENG":"Got the car keys?","TWN":"你帶車鑰匙了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그야 당연하죠. 여기 주머니에…","JPN":"もちろんだわ。ここのポケットに……","ENG":"Of course. It's here, in my pocket–","TWN":"當然，在我的口袋裡……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"조심해, 꼬맹이!","JPN":"おこちゃま、気をつけろ！","ENG":"Watch out, kid!","TWN":"小鬼小心！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"꺄아앗…!","JPN":"きゃああっ……！","ENG":"Kyaa...!","TWN":"啊啊……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"침식체가… 사람을 본 체도 않고 지나쳤어?","JPN":"侵食体が……人間を無視して通り過ぎた？","ENG":"A C.O... just walked right past a person.","TWN":"侵蝕體……直接忽略人類？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"방금 어떻게 된 거죠?","JPN":"今の、どういうことですか？","ENG":"What just happened?","TWN":"剛才是怎麼回事？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 침식체는 사람에게 적대적이지 않은 착한 침식체라거나?","JPN":"あの侵食体は人に敵対しない優しい侵食体とか？","ENG":"Could that be a nice C.O. that isn't hostile to humans?","TWN":"難道那個侵蝕體是對人類沒有敵意的善良侵蝕體？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"빨리 타. 저 침식체들을 쫓아가봐야겠어.","JPN":"早く乗れ。あの侵食体を追いかけるぞ。","ENG":"Get in the car. We're going to go after those C.O.s.","TWN":"上車，我要去追那些侵蝕體。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네에?! 제정신으로 하는 소리예요?","JPN":"ええ！？　本気なの？","ENG":"Huh?! Are you crazy?!","TWN":"什麼？！你瘋了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"애초에 지금의 상황부터가 정상이 아니야.","JPN":"そもそも今の状況から普通じゃないだろ。","ENG":"This situation is what's crazy.","TWN":"我們眼前的情況就已經很瘋狂了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"샤레이드 한복판에 버젓이 침식체들이 돌아다니는 것도 모자라, 뭔가에 홀린 것처럼 한 방향으로만 움직이고 있다고.","JPN":"シャレードの真ん中に侵食体が堂々とうろついてる上、何かに誘われるように一定の方向に向かっているんだぞ。","ENG":"Not only are there C.O.s strolling in the streets of Charade, but they're also moving in one direction, like they're being drawn to something.","TWN":"查雷德中心突然冒出了侵蝕體，而且像是被什麼東西迷惑了一樣，全部都往同一個方向前進。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저쪽에 무슨 맛있는 냄새라도 나는가 보죠! 지금 그걸 우리가 신경 쓸 때인가요?","JPN":"あっちからなんか美味しい匂いでもしてるんでしょ！　今私たちがそれを気にしてる場合なの？","ENG":"Maybe they smell something good in that direction! But it's none of our concern!","TWN":"也許從那裡傳來了什麼好吃的味道吧！我們管不了這些啊？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대피령이 떨어졌으니 얌전히 쉘터로 이동하자고요!","JPN":"避難命令が出てるんですよ！　大人しくシェルターに移動するわよ！","ENG":"They issued an evacuation order, so let's head to a shelter!","TWN":"疏散命令已經下達了，我們趕快去庇護所吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"부족한 탄약도 보충했겠다.","JPN":"弾薬も補充したことだし。","ENG":"I just got more ammunition.","TWN":"既然彈藥也補充了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 챔피언이 꼴사납게 도망치는 꼴을 중계할 순 없잖아?","JPN":"シャレードのガントレットチャンピオンが、みっともなく逃げる様を中継されるわけにはいかないだろ？","ENG":"And you wouldn't want Charade's Gauntlet champions to be caught on camera while running away, do you?","TWN":"總不能讓他們轉播查雷德聖鎧冠軍倉皇逃跑的畫面吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그건 그렇긴 하지만…","JPN":"そ、それはそうだけど……","ENG":"N-no, but...","TWN":"嗯，是沒錯，但是……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 침식체들을 이렇게 일사분란하게 움직이게 할만큼 맛있는 냄새라면.","JPN":"それに、侵食体が脇目も振らず向かうほどの匂いなら……","ENG":"And if the smell is good enough to make all these C.O.s move in perfect order.","TWN":"能吸引這麼多侵蝕體的味道……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"난 그 맛있는 게 뭔지 확인해 봐야겠거든.","JPN":"私はその美味しいもんが何なのか、確認してみないと気が済まないんだ。","ENG":"I want to know what's causing that smell.","TWN":"我倒想看看到底是什麼東西。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치도 없는데, 운전은 할 줄 아는 거예요?","JPN":"コーチもいないのに、運転は大丈夫なんですか？","ENG":"Coach isn't here, though. Do you even know how to drive?","TWN":"教練不在，你會開車嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"알지. 시동, 기어, 악셀, 앞에 낭떠러지가 있으면 브레이크!","JPN":"できるよ。エンジンかける、ギアを入れる、アクセルを踏む、前に崖があったらブレーキ！","ENG":"Of course. Start the car, shift into gear, floor the gas pedal, and stop if there's a cliff ahead!","TWN":"當然了。起動，打擋，踩油門，如果前方有懸崖就刹車！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그거 어제 봤던 레이싱 영화 대사…!","JPN":"それは昨日見たレース映画のセリフ……！","ENG":"That's from that racing movie we watched yesterday–","TWN":"這不是昨天賽車電影的台詞嗎……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"방어선을 지켜. 한 놈이라도 통과시켜선 안 돼.","JPN":"防御線を守れ。一匹もここを通すな。","ENG":"Hold the line. Don't let even a single one get through.","TWN":"守住防線，別讓任何一個人越過。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"방어선 후방에 오거 타입 침식체!","JPN":"防御線の後方にオーガタイプの侵食体です！","ENG":"Ogre-type C.O. at the back of the line!","TWN":"防線後方出現食人魔侵蝕體！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"땅밑을 통과한 건가? 지성도 없는 침식체가 어떻게 저런 판단을…?","JPN":"地中を通ったのか？　知性のない侵食体がどうやってそんな判断を……？","ENG":"Did it travel underground? How did a mindless C.O. know to make that kind of decision...?","TWN":"他是從地下穿過來的嗎？ 沒有思想的侵蝕體怎麼會做出這樣的判斷……？"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"녀석이 호텔로 향하고 있다! 입구를 폐쇄해!","JPN":"やつはホテルに向かってる！　入口を封鎖しろ！","ENG":"It's heading to the hotel! Close off the entrance!","TWN":"他向飯店跑了！封閉入口！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"잠깐! 놈이 벽을 타고 올라간다!","JPN":"待て！　やつが壁を登っているぞ！","ENG":"Wait! It's climbing up the wall!","TWN":"等等！他在爬牆！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"설마 창문으로…?","JPN":"まさか、窓から……？","ENG":"Is it trying to break through the windows...?","TWN":"難道是想透過窗戶……？"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"빨리 안쪽에 연락해! 요인이 위험하다!","JPN":"早く中に連絡しろ！　要人が危ない！","ENG":"Call someone inside! The VIP is in danger!","TWN":"快通知裡面的人！有危險！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"엇…?","JPN":"あっ……？","ENG":"Huh...?","TWN":"啊……？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"녀석이 다시 떨어진다! 조심해!","JPN":"やつが落ちてくる！　気をつけろ！","ENG":"It's falling down! Watch out!","TWN":"他又掉下去了！小心！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"뭐, 뭐야? 뭔가에 맞은 건가?","JPN":"な、何だ？　何かに当たったのか？","ENG":"W-what happened? Was it shot by something?","TWN":"怎、怎麼回事？被什麼東西打中了？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"누군가 탄을 쏴서 처치했군.","JPN":"誰かが弾丸を撃って倒したようだ。","ENG":"Someone shot a bullet through it.","TWN":"有人開火了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"단단한 오거 타입의 몸통에 구멍이 뚫어버릴 정도의 화력이라니.","JPN":"硬いオーガタイプの胴体に穴が開くほどの火力って……","ENG":"It was strong enough to penetrate the hard, Ogre-type flesh.","TWN":"好強的火力，竟然打穿食人魔。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"으아, 깜짝 놀랐네.","JPN":"うわ、ビックリした。","ENG":"Whoa. That scared me.","TWN":"啊，嚇我一跳。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"갑자기 창문으로 침식체가 튀어나올 줄이야.","JPN":"いきなり窓から侵食体が入ってくるなんて。","ENG":"I didn't think a C.O. would pop up on our window.","TWN":"我沒想到侵蝕體會突然從窗戶跳出來。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님은 괜찮아?","JPN":"社長は大丈夫？","ENG":"Are you all right, Boss?","TWN":"老闆還好嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"덕분에 무사하네.","JPN":"おかげさまで無事だ。","ENG":"Yes, thanks to you.","TWN":"嗯，幸好有你。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"금방 진압될 줄 알았는데, 작은 문제가 아닌 모양이군.","JPN":"すぐ鎮圧されると思っていたのだが、思ったよりも事は大きいようだな。","ENG":"I thought it would be taken care of quickly, but I guess it's not a small issue.","TWN":"我以為很快就能平息的，但看來不是一個小問題。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자님…!","JPN":"最高管理者……！","ENG":"Supreme Administrator...!","TWN":"最高管理者……！"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"크음.","JPN":"ゴホン。","ENG":"Ahem.","TWN":"咳。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"둘 다 무사하네. 침식체가 여기까지 습격해왔다고 들었는데.","JPN":"二人とも無事か。侵食体がここまで襲撃してきたと聞いたが。","ENG":"You're both safe. I heard a C.O. made its way up here.","TWN":"你們兩個都平安無事。我聽說侵蝕體攻到了這裡。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그거라면 걱정 말게. 침입자는 여기 미나 양이 훌륭하게 제압해줬으니까.","JPN":"それなら心配無用だ。侵入者は、ミナ君が見事制圧してくれたからな。","ENG":"No need to worry. Mina here did an excellent job handling the intruder.","TWN":"不用擔心。這裡的入侵者已經讓米娜已經迅速解決了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하하…","JPN":"ハハ……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"제압 과정에서 창문이 박살 나버렸는데, 변상해야 하는 건 아니겠지?","JPN":"制圧する途中で窓が割れちゃったけど、弁償はしなくていいよね？","ENG":"I broke the window handling them. Will I have to compensate the hotel for it?","TWN":"在解決過程中不小心打碎了窗戶，應該不會要求賠償吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그건 관리국 측에서 해결하지. 용의자는 신경 쓸 것 없어.","JPN":"それは管理局で解決しよう。容疑者は気にするな。","ENG":"The Administration will take care of that. You're a suspect, so rest easy.","TWN":"那是管理局是事，不用嫌犯操心。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방비로 둘째가라면 서러울 샤레이드에서 이번엔 대규모 침식재난이라니 별일이군.","JPN":"防備では一二を争うシャレードで、今度は大規模の侵食災害とは珍しい。","ENG":"Odd to see a large-scale Corruption disaster in a city as defense-focused as Charade.","TWN":"以防備著稱的查雷德竟然會發生如此大規模的侵蝕災難。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"침식의 완전 통제가 불가능하다곤 하지만… 이건 확실히 정상적인 상황은 아니야.","JPN":"侵食の完全統制が不可能だとは言え……確かにこれは正常な状況ではないな。","ENG":"It isn't possible to have complete control over Corruption, but... this isn't normal.","TWN":"雖然說侵蝕是無法完全控制的……但現在這確實不是正常情況。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바깥의 상황은 어떻지?","JPN":"外の状況はどうだ？","ENG":"What's the situation like outside?","TWN":"外面怎麼樣了？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"대 침식전에 투입될 인원을 제외한 비무장 시민들은 비상 쉘터로 모두 대피했어.","JPN":"対侵食戦に投入する人員を除いた非武装の市民は、全員非常シェルターに避難した。","ENG":"All unarmed citizens have evacuated to an emergency shelter, excluding people who are going to be deployed in anti-Corruption warfare.","TWN":"除了那些部署到侵蝕戰中的人員外，其他非武裝市民都已安全疏散到庇護所了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트가 이런 상황에 대비한 매뉴얼은 철저하게 준비해뒀더라고.","JPN":"リヒャルトがこういった状況に備えたマニュアルをしっかりと準備してくれていたんだ。","ENG":"Apparently, Richard made sure to prepare a manual for these kinds of situations.","TWN":"理查針對這種情況的應對還是很周全的。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 불행 중 다행이군.","JPN":"それは不幸中の幸いであったな。","ENG":"That's one good news.","TWN":"真是不幸中的萬幸。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드 시니어의 대행은 자네가 맡고 있는 건가?","JPN":"シャレードのシニア代行は君が担当しているのか？","ENG":"Then, are you the acting Senior of Charade?","TWN":"是你在代理查雷德Senior的職務嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"일단은. 비서관에게 인계할 수도 있겠지만, 시국을 감안해 내가 직임을 병행하게 됐어.","JPN":"とりあえずはね。秘書官に引き渡すこともできたが、現状を踏まえて私が職務を並行することにしたんだ。","ENG":"For now. I can hand it over to the secretary officer, but I'm taking on both duties in consideration of the current situation.","TWN":"暫時是。其實可以交付給秘書，但考慮到現在的局勢，還是由我來接手了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아무리 상황이 급박해져도 이 권한을 당신에게 넘겨줄 생각은 없으니 꿈 깨라고.","JPN":"いくら緊急を要する状況でも、この権限をあなたに渡すつもりはないから諦めな。","ENG":"I won't be handing you this authority no matter how desperate times get, so you can forget about that.","TWN":"無論情況變得多麼緊急，我都不會把這個權限交給你，所以你還是別做夢了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"적임자가 잘 해주고 있는데 내가 왜 그런 생각을 하겠나?","JPN":"適任者がいるのに、私がそんなことを考えるはずなかろう。","ENG":"And why would I even conceive such an idea when the right person is on the job?","TWN":"既然你做得這麼好，我又怎麼會這麼想呢？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…흥.","JPN":"……ふんっ。","ENG":"...Hmpf.","TWN":"……哼。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시니어님! 방금 전 컨트롤 쉘터 근처에서 3종 침식체의 접근이 감지됐습니다.</color>","JPN":"<color=#ffd34c>シニア！　先ほど、コントロールシェルターの近くで第3種侵食体の接近を感知しました。</color>","ENG":"<color=#ffd34c>Ma'am! We just detected a Category 3 C.O. approaching near the control shelter.</color>","TWN":"<color=#ffd34c>Senior！剛剛在庇護所附近發現3類侵蝕體在靠近。</color>"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그럼 지금 당장 가용할 수 있는 태스크포스를 동원해서 막아!","JPN":"では、今すぐ動けるタスクフォースを動員して阻止しろ！","ENG":"Gather all the available TASKFORCEs and stop it!","TWN":"馬上調動可用的特遣勢力來阻止他！"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이미 호출은 시도하고 있습니다만…</color>","JPN":"<color=#ffd34c>すでに呼び出してはいるのですが……</color>","ENG":"<color=#ffd34c>We've been trying to call them, but...</color>","TWN":"<color=#ffd34c>我已經在嘗試呼叫了，但是……</color>"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>3종에 대응이 가능한 샤레이드의 태스크포스들은 전부 다른 곳에 발이 묶인 상황입니다.</color>","JPN":"<color=#ffd34c>第3種に対応可能なシャレードのタスクフォースは、すべて他の場所で足止めされています。</color>","ENG":"<color=#ffd34c>All of Charade's TASKFORCEs that can handle a Category 3 C.O. are busy elsewhere.</color>","TWN":"<color=#ffd34c>有能力應對3類侵蝕體的查雷德特遣勢力，現在都派到了其他地方。</color>"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…뭐?","JPN":"……何だと？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"충원 가능한 근처 병력을 소집해서 최대한 시간을 벌어. 내가 지금 그리로 갈 테니까.","JPN":"補充できる近くの兵力を召集して、なるべく時間を稼げ。直ちにそちらへ向かう。","ENG":"Gather the troops nearby and buy as much time as you can. I'll head over there now.","TWN":"召集附近的部隊，儘量爭取時間，我現在就過去。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신들은 가드를 붙여줄 테니 지하로 대피해.","JPN":"あなたたちにはガードをつけてあげるから、地下に避難しろ。","ENG":"I'll assign you a bodyguard. Go underground and take shelter.","TWN":"我會給你們安排保鑣，快疏散到地下吧。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 편이 여기 남아있는 것보다 안전할 거야.","JPN":"ここに残っているより、その方が安全だろう。","ENG":"It'll be safer than staying here.","TWN":"這樣比待在這裡更安全。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Hey.","TWN":"那個……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내가 도와 줄게. 우리도 일단은 태스크포스거든.","JPN":"私が助けてあげる。私たちも一応はタスクフォースなんだから。","ENG":"I can help. We are technically a TASKFORCE.","TWN":"我來幫你，我們也是特遣勢力。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"됐어. 부상을 입은 용의자 손까지 빌릴 정도로 절박한 상황은 아니야.","JPN":"いいや。手負いの容疑者に助けられるほど、緊迫した状況ではない。","ENG":"No thanks. I'm not so desperate that I'd accept help from an injured suspect.","TWN":"算了，情況還沒有惡劣到向一個受傷的嫌犯請求幫助。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"유력한 범인이 밝혀진 시점에서 더 이상 내 직원을 용의자 취급할 필요는 없어 보이는데.","JPN":"有力な犯人が明らかになった時点で、これ以上私の職員を容疑者扱いする必要はないだろう。","ENG":"I don't see the need to treat my employee like a suspect anymore, since we know who's likely to be the culprit.","TWN":"既然已經找到了重大嫌犯，就沒有必要再把我的員工當作嫌犯了吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>날 봐서라도</color> 한 번 믿고 맡겨보는 게 어떻겠나?","JPN":"<color=#ffd34c>私のためにも</color>一度だけ信頼して任せてみるのはどうかね？","ENG":"How about you give her a shot, if not for yourself, than <color=#ffd34c>for me</color>.","TWN":"<color=#ffd34c>你不妨看在我的面子上</color>，就相信一次吧 ？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"꼭 문장 앞에 <color=#ffd34c>그런 표현</color>을 붙여야겠어?","JPN":"<color=#ffd34c>その言葉</color>は本当に必要だったのか？","ENG":"Did you really have to use <color=#ffd34c>those words</color>?","TWN":"非要在前面加上<color=#ffd34c>那句話</color>嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일단은 나도 명함은 태스크포스 사장이니까.","JPN":"私も一応、タスクフォースの社長なのでな。","ENG":"Well, strictly speaking, I am the CEO of a TASKFORCE.","TWN":"畢竟我現在依然是特遣勢力的老闆。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥.","JPN":"ふんっ。","ENG":"Hmpf.","TWN":"哼。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"따라와. 샤레이드 병기고에 3종에도 유효한 카운터 장비가 있어.","JPN":"ついて来い。シャレードの兵器庫に第3種にも有効なカウンターの装備がある。","ENG":"Follow me. There are Counter gear that'll work on Category 3s in Charade's armory.","TWN":"跟我來，查雷德武器庫裡有一些可以應對3類侵蝕體的制裁者裝備。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"특별히 다룰 줄 아는 타입의 무기가 있나?","JPN":"愛用している武器はあるか？","ENG":"Is there a particular weapon you prefer to use?","TWN":"你有什麼特別擅長的武器嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사복검만 제외하면 웬만한 건 다 있을 거야.","JPN":"蛇腹剣以外なら、ほぼ揃っているぞ。","ENG":"They should have almost everything besides whip swords.","TWN":"除了蛇腹劍，其他的應該都能找到。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"고마워. 하지만 괜찮아.","JPN":"ありがとう。でも大丈夫。","ENG":"I appreciate the offer. I'll be fine, though.","TWN":"謝謝，不過沒關係。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"난 내 거 하나로 충분하거든.","JPN":"私はこれ一つで十分だから。","ENG":"My own weapon is good enough for me.","TWN":"我用我自己的就行了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};